#!/usr/bin/env bash
#
# Downloads the LDBC FinBench SF0.01 dataset and converts the relevant
# pipe-delimited CSV files to JSONL for use with the datalog package.
#
# The FinBench dataset is generated by ldbc/ldbc_finbench_datagen,
# licensed under the Apache License 2.0.
# See https://github.com/ldbc/ldbc_finbench_datagen for details.
#
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
DATA_DIR="$SCRIPT_DIR/data"
JSONL_DIR="$SCRIPT_DIR/data/jsonl"

SF="sf0.01"
URL="https://datasets.ldbcouncil.org/finbench/${SF}.tar.gz"

mkdir -p "$DATA_DIR" "$JSONL_DIR"

# Download if not already present
if [ ! -d "$DATA_DIR/$SF" ]; then
    echo "Downloading $URL ..."
    curl -L "$URL" | tar xz -C "$DATA_DIR"
fi

SNAPSHOT="$DATA_DIR/$SF/snapshot"

# csv2jsonl: convert a pipe-delimited CSV (with header row) to JSONL.
csv2jsonl() {
    local infile="$1"
    local outfile="$2"
    awk -F'|' '
    NR==1 {
        for (i=1; i<=NF; i++) header[i] = $i
        ncols = NF
        next
    }
    {
        printf "{"
        for (i=1; i<=ncols; i++) {
            if (i>1) printf ","
            gsub(/\\/, "\\\\", $i)
            gsub(/"/, "\\\"", $i)
            printf "\"%s\":\"%s\"", header[i], $i
        }
        print "}"
    }' "$infile" > "$outfile"
}

echo "Converting CSV -> JSONL ..."

csv2jsonl "$SNAPSHOT/PersonOwnAccount.csv"        "$JSONL_DIR/person_own_account.jsonl"
csv2jsonl "$SNAPSHOT/AccountTransferAccount.csv"   "$JSONL_DIR/account_transfer.jsonl"
csv2jsonl "$SNAPSHOT/CompanyOwnAccount.csv"        "$JSONL_DIR/company_own_account.jsonl"
csv2jsonl "$SNAPSHOT/Person.csv"                   "$JSONL_DIR/person.jsonl"
csv2jsonl "$SNAPSHOT/Account.csv"                  "$JSONL_DIR/account.jsonl"
csv2jsonl "$SNAPSHOT/Company.csv"                  "$JSONL_DIR/company.jsonl"

echo "Done. JSONL files in $JSONL_DIR"
echo
wc -l "$JSONL_DIR"/*.jsonl
